  const fechaValida = /^\d{2}-\d{2}-\d{4}$/.test(fecha);

  if (!tlfValido) {
    alert("Teléfono inválido. Debe tener 9 dígitos y empezar por 6, 7 o 9.");
  }
  if (!fechaValida) {
    alert("Fecha inválida. Debe tener formato dd-mm-aaaa.");
  }

  // Solo almacenar si ambas validaciones pasan
  if (tlfValido && fechaValida) {
    nombres.push(nombre.toLowerCase());
    apellidos.push(apellido.toLowerCase());
    fechasNac.push(fecha);
    telefonos.push(tlf);
  }
}

