  getNacimiento() { return this.#fechaNacimiento; }

  setNombre(n) { if (n.trim() !== "") this.#nombre = n; }
  setApellido(a) { if (a.trim() !== "") this.#apellido = a; }
  setNacimiento(f) { if (f.trim() !== "") this.#fechaNacimiento = f; }
}

class PersonaCivil extends Persona {
  #dni;
  #telefono;

  constructor(nombre, apellido, fechaNacimiento, dni, telefono) {
    super(nombre, apellido, fechaNacimiento);
    this.#dni = dni;
    this.#telefono = telefono;
  }

  getDNI() { return this.#dni; }
  getTelefono() { return this.#telefono; }
  setDNI(d) { if (d.trim() !== "") this.#dni = d; }
  setTelefono(t) { if (t.trim() !== "") this.#telefono = t; }

