// 2. Validar fecha (dd/mm/aaaa) y edad > 16 al salir del campo
document.getElementById("fechaNac").addEventListener("blur", function() {
  const val = this.value.trim();
  const regex = /^\d{2}\/\d{2}\/\d{4}$/;
  if (!regex.test(val)) {
    alert("Formato fecha inválido. Use dd/mm/aaaa.");
    return;
  }
  const [dia, mes, anyo] = val.split("/").map(Number);
  const nacimiento = new Date(anyo, mes - 1, dia);
  const hoy = new Date();
  let edad = hoy.getFullYear() - nacimiento.getFullYear();
  const m = hoy.getMonth() - nacimiento.getMonth();
  if (m < 0 || (m === 0 && hoy.getDate() < nacimiento.getDate())) {
    edad--;
  }
  if (edad <= 16) {
    alert("Debe ser mayor de 16 años.");
  }
});

// 3. Validar DNI (8 dígitos + letra) al salir
document.getElementById("dni").addEventListener("blur", function() {
  const regex = /^\d{8}[A-Za-z]$/;
  if (!regex.test(this.value.trim())) {
    alert("DNI inválido. Debe tener 8 dígitos y una letra.");
  }
});

