<!DOCTYPE html>
<html>
<head><title>Buscar País</title></head>
<body>
  <h1>Buscar información de un país</h1>
  <input type="text" id="paisInput" placeholder="Nombre del país">
  <button id="btnBuscar">Buscar</button>
  <div id="resultado"></div>

  <script>
  document.getElementById("btnBuscar").addEventListener("click", function() {
    const nombre = document.getElementById("paisInput").value.trim();
    if (!nombre) return;

    const xhr = new XMLHttpRequest();
    xhr.open("GET", "https://restcountries.com/v3.1/name/" + nombre);
    xhr.onload = function() {
      if (xhr.status === 200) {
        const datos = JSON.parse(xhr.responseText);
        const pais = datos[0];
        const monedas = Object.values(pais.currencies)
          .map(m => m.name + " (" + m.symbol + ")").join(", ");

        document.getElementById("resultado").innerHTML =
          "<p><strong>Capital:</strong> " + (pais.capital ? pais.capital[0] : "N/A") + "</p>" +
          "<p><strong>Población:</strong> " + pais.population.toLocaleString() + "</p>" +
          "<p><strong>Moneda:</strong> " + monedas + "</p>";
      } else {
        alert("País no encontrado. Verifica el nombre.");
      }
    };
    xhr.onerror = function() {
      alert("Error de conexión.");
    };
    xhr.send();
  });
  </script>
</body>
</html>
