  <button id="btnBuscar">Buscar</button>
  <ul id="listaPaises"></ul>

  <script>
  $("#btnBuscar").on("click", function() {
    const idioma = $("#idiomaInput").val().trim();
    if (!idioma) return;

    $.ajax({
      url: "https://restcountries.com/v3.1/lang/" + idioma,
      method: "GET",
      success: function(datos) {
        let html = "";
        datos.forEach(function(pais) {
          html += "<li>" + pais.name.common + "</li>";
        });
        $("#listaPaises").html(html);
      },
      error: function() {
        alert("Código de idioma no válido o sin resultados.");
      }
    });
  });
  </script>
</body>
</html>
